import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"RFC-006 ‚Äî Porkchop plot mobile interaction model","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-006.md","filePath":"rfc/RFC-006.md"}'),n={name:"rfc/RFC-006.md"};function r(s,e,l,h,c,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-006-‚Äî-porkchop-plot-mobile-interaction-model" tabindex="-1">RFC-006 ‚Äî Porkchop plot mobile interaction model <a class="header-anchor" href="#rfc-006-‚Äî-porkchop-plot-mobile-interaction-model" aria-label="Permalink to &quot;RFC-006 ‚Äî Porkchop plot mobile interaction model&quot;">‚Äã</a></h1><blockquote><p>Status ¬∑ Draft v0.1 TA anchor ¬∑ ¬ßcomponents/plan-screen Related PRD ¬∑ PRD-002 Related ADR ¬∑ ADR-018 (mobile-first) Closes into ¬∑ ADR (pending) Why this is an RFC ¬∑ The porkchop plot is a 112√ó100 grid where each cell is ~3‚Äì4px. A finger covers ~44px. Direct tap-to-select is impossible at native size. The mobile interaction model is a genuine open question with three distinct approaches, each producing a different user experience.</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">‚Äã</a></h2><p>On desktop the porkchop plot is a dense colour grid ‚Äî hover for a tooltip, click a cell to select a launch window. On mobile at 390px wide, each cell is ~3px. Touch interaction requires a fundamentally different approach.</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">‚Äã</a></h2><ul><li>Mobile user wants to find the best launch window for a Mars mission</li><li>Mobile user wants to explore different departure/arrival combinations</li><li>Mobile user wants to select a specific window and fly it</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">‚Äã</a></h2><ul><li>The user can find and select a viable launch window on mobile</li><li>The interaction feels native ‚Äî not a shrunken desktop experience</li><li>The educational value of the porkchop plot (seeing launch windows as coloured valleys) is preserved on mobile</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">‚Äã</a></h2><p>From ADR-018: mobile-first, 44px touch targets. From ADR-009: the fly screen needs a departure date and arrival date to initialise the trajectory.</p><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">‚Äã</a></h2><p><strong>Option A ‚Äî Pinch-to-zoom grid.</strong> The full porkchop plot is shown at native resolution. The user pinches to zoom in to a region of interest, then taps a cell at the zoomed scale. A mini-map in the corner shows position within the full grid.</p><p>Preserves the full porkchop experience on mobile. More complex to implement (zoom + pan on a canvas). Zoomed cells need larger labels. The educational overview (seeing the whole pattern) is preserved.</p><p><strong>Option B ‚Äî Dual date sliders.</strong> Replace the 2D grid with two sliders: departure date range and arrival date range. The best delta-v window within the selected ranges is highlighted automatically. The user narrows the sliders to explore. A simplified 1D cost graph shows the delta-v profile as sliders move.</p><p>Most mobile-native interaction. Lower implementation complexity. Educational loss: the 2D porkchop pattern ‚Äî the thing that makes launch windows visually legible ‚Äî is not shown. The user gets the answer without the insight.</p><p><strong>Option C ‚Äî Tap-to-explore with magnifier.</strong> The full plot is shown but too small to tap precisely. Tapping anywhere in the grid opens a magnifier bubble (like iOS text selection) showing a 5√ó5 cell region at large scale. The user slides their finger to navigate the magnifier, lifts to select. Standard mobile pattern for precise selection in dense content.</p><p>Good balance: preserves the full visual overview, mobile-native selection pattern, no zoom/pan complexity. The magnifier UX is familiar from iOS. Implementation is moderate complexity.</p><h2 id="proposed-approach" tabindex="-1">Proposed approach <a class="header-anchor" href="#proposed-approach" aria-label="Permalink to &quot;Proposed approach&quot;">‚Äã</a></h2><p><strong>Option C</strong> for v1 ‚Äî magnifier pattern. Preserves the educational porkchop overview while enabling precise selection on mobile. Option A is the richer experience and a strong v2 candidate once the mobile baseline is established.</p><p>Desktop interaction unchanged: hover tooltip, click to select.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">‚Äã</a></h2><p><strong>Option A</strong> ‚Äî richest experience; higher implementation cost; deferred to v2. <strong>Option B</strong> ‚Äî loses the porkchop visual; the educational core of PRD-002 is the colour pattern, not just the selected date; rejected.</p><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">‚Äã</a></h2><p>The magnifier is a familiar pattern but adds implementation complexity. The alternative (zoom/pan) is richer but adds more complexity. Option B is simpler but loses the educational core.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">‚Äã</a></h2><ol><li>Should the magnifier show delta-v values numerically inside each enlarged cell?</li><li>What happens when the user lifts their finger outside the plot area ‚Äî cancel or select nearest cell?</li><li>Should there be a &quot;best window&quot; auto-suggest button for users who don&#39;t want to explore manually?</li></ol><h2 id="closing-evidence" tabindex="-1">Closing evidence <a class="header-anchor" href="#closing-evidence" aria-label="Permalink to &quot;Closing evidence&quot;">‚Äã</a></h2><p>Mobile interaction tested on real iOS and Android devices. User can find and select a viable launch window without assistance. Available at Slice 3 gate.</p><h2 id="how-this-closes" tabindex="-1">How this closes <a class="header-anchor" href="#how-this-closes" aria-label="Permalink to &quot;How this closes&quot;">‚Äã</a></h2><p>One ADR: the porkchop plot mobile interaction pattern for v1.</p>',30)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
